module portfolio_optimizer(  
    input [1:0] asset1,  
    input [1:0] asset2,  
    input [1:0] asset3,  
    output [3:0] total_weight  
);  
      wire _n01 = asset1 + asset2[0] ^ asset3[0];
  wire _c01 = asset1 + asset2[0] & asset3[0];
  wire _n02 = asset1 + asset2[1] ^ asset3[1] ^ _c01;
  wire _c02 = (asset1 + asset2[1] & asset3[1]) | (asset1 + asset2[1] & _c01) | (asset3[1] & _c01);
  wire _n03 = asset1 + asset2[2] ^ asset3[2] ^ _c02;
  wire _c03 = (asset1 + asset2[2] & asset3[2]) | (asset1 + asset2[2] & _c02) | (asset3[2] & _c02);
  wire _n04 = asset1 + asset2[3] ^ asset3[3] ^ _c03;
  wire _c04 = (asset1 + asset2[3] & asset3[3]) | (asset1 + asset2[3] & _c03) | (asset3[3] & _c03);
  assign total_weight = {_n01, _n02, _n03, _n04};  
endmodule
